func canOpenURL(_ url: URL) -> Bool {
    return (url.scheme == "https") && ([url.pathComponents[1], url.pathComponents[2]].contains("myapp"))
}

func application(_ application: UIApplication, continue userActivity: NSUserActivity, restorationHandler: @escaping ([UIRestorationContextMappingKey : Any]?) -> Void) -> Bool {
    if userActivity.activityType == NSUserActivityTypeBrowsingWeb {
        if canOpenURL(userActivity.webpageURL!) {
            let urlComponents = URLComponents(url: userActivity.webpageURL!, resolvingAgainstBaseURL: false)!
            switch urlComponents.path {
            case "/profile/\(let id)":
                let vc = UIStoryboard(name: "Main", bundle: nil).instantiateViewController(withIdentifier: "ProfileViewController") as! ProfileViewController
                vc.userId = Int(id)
                window?.rootViewController?.present(vc, animated: true, completion: nil)
            case "/payment/confirm":
                let vc = UIStoryboard(name: "Main", bundle: nil).instantiateViewController(withIdentifier: "PaymentConfirmationViewController") as! PaymentConfirmationViewController
                window?.rootViewController?.present(vc, animated: true, completion: nil)
            case "/admin/settings":
                let vc = UIStoryboard(name: "Main", bundle: nil).instantiateViewController(withIdentifier: "AdminSettingsViewController") as! AdminSettingsViewController
                window?.rootViewController?.present(vc, animated: true, completion: nil)
            default:
                break
            }
            return true
        }
    }
    return false
}

